/**
 * Webhook notification handler for order lifecycle events.
 *
 * Subscribes to order events via EventBus and dispatches HTTP webhook
 * callbacks to registered URLs. Follows the same EventBus subscription
 * pattern as NotificationService and EmailNotificationHandler.
 *
 * Depends on:
 * - EventBus (event system) for receiving order events
 */

import type { EventBus } from '../events/event-bus.js';
import type { OrderCreatedEvent, OrderStatusChangedEvent } from '../events/event-types.js';
import type { EventType } from '../events/event-types.js';
import { Logger } from '../utils/logger.js';

export type WebhookEventType = 'order:created' | 'order:status-changed';

export interface WebhookRegistration {
  id: string;
  url: string;
  eventTypes: WebhookEventType[];
  secret?: string;
  createdAt: Date;
}

export interface WebhookDelivery {
  id: string;
  registrationId: string;
  url: string;
  eventType: EventType;
  payload: Record<string, unknown>;
  status: 'success' | 'failed';
  statusCode?: number;
  error?: string;
  deliveredAt: Date;
}

export interface WebhookDispatcher {
  dispatch(url: string, payload: Record<string, unknown>, secret?: string): Promise<{ success: boolean; statusCode?: number; error?: string }>;
}

/**
 * Default dispatcher that simulates HTTP delivery (in-memory for this demo).
 * In production, this would use fetch/http to POST to the URL.
 */
export class InMemoryWebhookDispatcher implements WebhookDispatcher {
  async dispatch(
    _url: string,
    _payload: Record<string, unknown>,
    _secret?: string,
  ): Promise<{ success: boolean; statusCode?: number; error?: string }> {
    return { success: true, statusCode: 200 };
  }
}

let nextRegistrationId = 1;
let nextDeliveryId = 1;

function generateRegistrationId(): string {
  return `webhook-${String(nextRegistrationId++).padStart(4, '0')}`;
}

function generateDeliveryId(): string {
  return `delivery-${String(nextDeliveryId++).padStart(4, '0')}`;
}

export function resetWebhookIdCounters(): void {
  nextRegistrationId = 1;
  nextDeliveryId = 1;
}

export class WebhookHandler {
  private logger = new Logger('WebhookHandler');
  private registrations: WebhookRegistration[] = [];
  private deliveries: WebhookDelivery[] = [];
  private dispatcher: WebhookDispatcher;

  constructor(
    private eventBus: EventBus,
    dispatcher?: WebhookDispatcher,
  ) {
    this.dispatcher = dispatcher ?? new InMemoryWebhookDispatcher();
    this.registerHandlers();
  }

  /**
   * Register event handlers via EventBus — same pattern as NotificationService.
   */
  private registerHandlers(): void {
    this.eventBus.on<OrderCreatedEvent>('order:created', (event) => {
      this.handleOrderCreated(event);
    });

    this.eventBus.on<OrderStatusChangedEvent>('order:status-changed', (event) => {
      this.handleOrderStatusChanged(event);
    });
  }

  /**
   * Register a webhook URL for specific event types.
   */
  registerWebhook(params: {
    url: string;
    eventTypes: WebhookEventType[];
    secret?: string;
  }): WebhookRegistration {
    const registration: WebhookRegistration = {
      id: generateRegistrationId(),
      url: params.url,
      eventTypes: params.eventTypes,
      secret: params.secret,
      createdAt: new Date(),
    };
    this.registrations.push(registration);
    this.logger.info(`Webhook registered: ${registration.id} -> ${params.url} for [${params.eventTypes.join(', ')}]`);
    return registration;
  }

  /**
   * Unregister a webhook by ID.
   */
  unregisterWebhook(id: string): boolean {
    const index = this.registrations.findIndex((r) => r.id === id);
    if (index === -1) {
      return false;
    }
    this.registrations.splice(index, 1);
    this.logger.info(`Webhook unregistered: ${id}`);
    return true;
  }

  /**
   * Get all registered webhooks.
   */
  getRegistrations(): WebhookRegistration[] {
    return [...this.registrations];
  }

  /**
   * Get registrations for a specific event type.
   */
  getRegistrationsForEvent(eventType: WebhookEventType): WebhookRegistration[] {
    return this.registrations.filter((r) => r.eventTypes.includes(eventType));
  }

  /**
   * Handle order created — dispatch webhooks to registered URLs.
   */
  private async handleOrderCreated(event: OrderCreatedEvent): Promise<void> {
    const payload: Record<string, unknown> = {
      event: 'order:created',
      orderId: event.order.id,
      userId: event.order.userId,
      items: event.order.items,
      total: event.order.total,
      status: event.order.status,
      timestamp: event.timestamp.toISOString(),
    };

    await this.dispatchToRegistered('order:created', payload);
  }

  /**
   * Handle order status change — dispatch webhooks to registered URLs.
   */
  private async handleOrderStatusChanged(event: OrderStatusChangedEvent): Promise<void> {
    const payload: Record<string, unknown> = {
      event: 'order:status-changed',
      orderId: event.order.id,
      userId: event.order.userId,
      previousStatus: event.previousStatus,
      newStatus: event.newStatus,
      timestamp: event.timestamp.toISOString(),
    };

    await this.dispatchToRegistered('order:status-changed', payload);
  }

  /**
   * Dispatch a payload to all webhooks registered for the given event type.
   */
  private async dispatchToRegistered(
    eventType: WebhookEventType,
    payload: Record<string, unknown>,
  ): Promise<void> {
    const targets = this.getRegistrationsForEvent(eventType);

    for (const registration of targets) {
      await this.deliverWebhook(registration, eventType, payload);
    }
  }

  /**
   * Deliver a webhook payload to a single registration.
   */
  private async deliverWebhook(
    registration: WebhookRegistration,
    eventType: EventType,
    payload: Record<string, unknown>,
  ): Promise<void> {
    this.logger.info(`Dispatching webhook ${registration.id} to ${registration.url}`);

    const result = await this.dispatcher.dispatch(
      registration.url,
      payload,
      registration.secret,
    );

    const delivery: WebhookDelivery = {
      id: generateDeliveryId(),
      registrationId: registration.id,
      url: registration.url,
      eventType,
      payload,
      status: result.success ? 'success' : 'failed',
      statusCode: result.statusCode,
      error: result.error,
      deliveredAt: new Date(),
    };

    this.deliveries.push(delivery);
    this.logger.info(
      `Webhook delivery ${delivery.id}: ${delivery.status} (${delivery.statusCode ?? 'N/A'})`,
    );
  }

  /**
   * Get all webhook deliveries.
   */
  getDeliveries(): WebhookDelivery[] {
    return [...this.deliveries];
  }

  /**
   * Get deliveries for a specific registration.
   */
  getDeliveriesForRegistration(registrationId: string): WebhookDelivery[] {
    return this.deliveries.filter((d) => d.registrationId === registrationId);
  }

  /**
   * Get the count of deliveries.
   */
  getDeliveryCount(): number {
    return this.deliveries.length;
  }

  /**
   * Clear all registrations and deliveries (useful for testing).
   */
  clearAll(): void {
    this.registrations = [];
    this.deliveries = [];
  }
}

import { describe, it, expect, beforeEach } from 'vitest';
import { EventBus } from '../../src/events/event-bus.js';
import {
  WebhookHandler,
  resetWebhookIdCounters,
} from '../../src/notifications/webhook-handler.js';
import type {
  WebhookDispatcher,
  WebhookDelivery,
} from '../../src/notifications/webhook-handler.js';
import type { OrderCreatedEvent, OrderStatusChangedEvent } from '../../src/events/event-types.js';

function makeOrderCreatedEvent(overrides?: Partial<OrderCreatedEvent>): OrderCreatedEvent {
  return {
    type: 'order:created',
    order: {
      id: 'order-0001',
      userId: 'user-0001',
      items: [
        { productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 10 },
      ],
      total: 20,
      status: 'pending',
      createdAt: new Date(),
      updatedAt: new Date(),
    },
    user: {
      id: 'user-0001',
      name: 'Alice',
      email: 'alice@example.com',
      role: 'member',
      createdAt: new Date(),
      updatedAt: new Date(),
    },
    timestamp: new Date(),
    ...overrides,
  };
}

function makeStatusChangedEvent(
  previousStatus: string,
  newStatus: string,
): OrderStatusChangedEvent {
  return {
    type: 'order:status-changed',
    order: {
      id: 'order-0001',
      userId: 'user-0001',
      items: [{ productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 10 }],
      total: 20,
      status: newStatus as 'confirmed',
      createdAt: new Date(),
      updatedAt: new Date(),
    },
    previousStatus,
    newStatus,
    timestamp: new Date(),
  };
}

/**
 * A mock dispatcher that records calls and allows controlling responses.
 */
class MockDispatcher implements WebhookDispatcher {
  calls: { url: string; payload: Record<string, unknown>; secret?: string }[] = [];
  private nextResult: { success: boolean; statusCode?: number; error?: string } = {
    success: true,
    statusCode: 200,
  };

  async dispatch(
    url: string,
    payload: Record<string, unknown>,
    secret?: string,
  ): Promise<{ success: boolean; statusCode?: number; error?: string }> {
    this.calls.push({ url, payload, secret });
    return this.nextResult;
  }

  simulateFailure(error: string, statusCode?: number): void {
    this.nextResult = { success: false, statusCode, error };
  }

  simulateSuccess(statusCode = 200): void {
    this.nextResult = { success: true, statusCode };
  }
}

describe('WebhookHandler', () => {
  let eventBus: EventBus;
  let dispatcher: MockDispatcher;
  let handler: WebhookHandler;

  beforeEach(() => {
    eventBus = new EventBus();
    dispatcher = new MockDispatcher();
    resetWebhookIdCounters();
    handler = new WebhookHandler(eventBus, dispatcher);
  });

  describe('webhook registration', () => {
    it('should register a webhook and return a registration', () => {
      const reg = handler.registerWebhook({
        url: 'https://example.com/hook',
        eventTypes: ['order:created'],
      });

      expect(reg.id).toBe('webhook-0001');
      expect(reg.url).toBe('https://example.com/hook');
      expect(reg.eventTypes).toEqual(['order:created']);
      expect(reg.createdAt).toBeInstanceOf(Date);
    });

    it('should register multiple webhooks with incrementing IDs', () => {
      const reg1 = handler.registerWebhook({
        url: 'https://a.com/hook',
        eventTypes: ['order:created'],
      });
      const reg2 = handler.registerWebhook({
        url: 'https://b.com/hook',
        eventTypes: ['order:status-changed'],
      });

      expect(reg1.id).toBe('webhook-0001');
      expect(reg2.id).toBe('webhook-0002');
    });

    it('should register a webhook with a secret', () => {
      const reg = handler.registerWebhook({
        url: 'https://example.com/hook',
        eventTypes: ['order:created'],
        secret: 'my-secret',
      });

      expect(reg.secret).toBe('my-secret');
    });

    it('should register a webhook for multiple event types', () => {
      const reg = handler.registerWebhook({
        url: 'https://example.com/hook',
        eventTypes: ['order:created', 'order:status-changed'],
      });

      expect(reg.eventTypes).toEqual(['order:created', 'order:status-changed']);
    });

    it('should unregister a webhook by ID', () => {
      const reg = handler.registerWebhook({
        url: 'https://example.com/hook',
        eventTypes: ['order:created'],
      });

      expect(handler.unregisterWebhook(reg.id)).toBe(true);
      expect(handler.getRegistrations()).toHaveLength(0);
    });

    it('should return false when unregistering a non-existent webhook', () => {
      expect(handler.unregisterWebhook('webhook-9999')).toBe(false);
    });

    it('should list all registrations', () => {
      handler.registerWebhook({ url: 'https://a.com', eventTypes: ['order:created'] });
      handler.registerWebhook({ url: 'https://b.com', eventTypes: ['order:status-changed'] });

      expect(handler.getRegistrations()).toHaveLength(2);
    });

    it('should filter registrations by event type', () => {
      handler.registerWebhook({ url: 'https://a.com', eventTypes: ['order:created'] });
      handler.registerWebhook({ url: 'https://b.com', eventTypes: ['order:status-changed'] });
      handler.registerWebhook({
        url: 'https://c.com',
        eventTypes: ['order:created', 'order:status-changed'],
      });

      expect(handler.getRegistrationsForEvent('order:created')).toHaveLength(2);
      expect(handler.getRegistrationsForEvent('order:status-changed')).toHaveLength(2);
    });
  });

  describe('order:created webhooks', () => {
    it('should dispatch to registered webhooks when an order is created', async () => {
      handler.registerWebhook({
        url: 'https://example.com/hook',
        eventTypes: ['order:created'],
      });

      await eventBus.emit(makeOrderCreatedEvent());

      expect(dispatcher.calls).toHaveLength(1);
      expect(dispatcher.calls[0]?.url).toBe('https://example.com/hook');
      expect(dispatcher.calls[0]?.payload).toMatchObject({
        event: 'order:created',
        orderId: 'order-0001',
        userId: 'user-0001',
        total: 20,
      });
    });

    it('should include order items in the payload', async () => {
      handler.registerWebhook({
        url: 'https://example.com/hook',
        eventTypes: ['order:created'],
      });

      await eventBus.emit(makeOrderCreatedEvent());

      const payload = dispatcher.calls[0]?.payload;
      expect(payload?.items).toEqual([
        { productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 10 },
      ]);
    });

    it('should not dispatch to webhooks registered for other event types', async () => {
      handler.registerWebhook({
        url: 'https://example.com/hook',
        eventTypes: ['order:status-changed'],
      });

      await eventBus.emit(makeOrderCreatedEvent());

      expect(dispatcher.calls).toHaveLength(0);
    });

    it('should dispatch to multiple registered webhooks', async () => {
      handler.registerWebhook({ url: 'https://a.com/hook', eventTypes: ['order:created'] });
      handler.registerWebhook({ url: 'https://b.com/hook', eventTypes: ['order:created'] });

      await eventBus.emit(makeOrderCreatedEvent());

      expect(dispatcher.calls).toHaveLength(2);
      expect(dispatcher.calls[0]?.url).toBe('https://a.com/hook');
      expect(dispatcher.calls[1]?.url).toBe('https://b.com/hook');
    });

    it('should pass the secret to the dispatcher', async () => {
      handler.registerWebhook({
        url: 'https://example.com/hook',
        eventTypes: ['order:created'],
        secret: 'my-secret',
      });

      await eventBus.emit(makeOrderCreatedEvent());

      expect(dispatcher.calls[0]?.secret).toBe('my-secret');
    });
  });

  describe('order:status-changed webhooks', () => {
    it('should dispatch when order status changes', async () => {
      handler.registerWebhook({
        url: 'https://example.com/hook',
        eventTypes: ['order:status-changed'],
      });

      await eventBus.emit(makeStatusChangedEvent('pending', 'confirmed'));

      expect(dispatcher.calls).toHaveLength(1);
      expect(dispatcher.calls[0]?.payload).toMatchObject({
        event: 'order:status-changed',
        orderId: 'order-0001',
        previousStatus: 'pending',
        newStatus: 'confirmed',
      });
    });

    it('should dispatch for each status transition', async () => {
      handler.registerWebhook({
        url: 'https://example.com/hook',
        eventTypes: ['order:status-changed'],
      });

      await eventBus.emit(makeStatusChangedEvent('pending', 'confirmed'));
      await eventBus.emit(makeStatusChangedEvent('confirmed', 'shipped'));
      await eventBus.emit(makeStatusChangedEvent('shipped', 'delivered'));

      expect(dispatcher.calls).toHaveLength(3);
    });
  });

  describe('delivery tracking', () => {
    it('should record successful deliveries', async () => {
      handler.registerWebhook({
        url: 'https://example.com/hook',
        eventTypes: ['order:created'],
      });

      await eventBus.emit(makeOrderCreatedEvent());

      const deliveries = handler.getDeliveries();
      expect(deliveries).toHaveLength(1);
      expect(deliveries[0]?.id).toBe('delivery-0001');
      expect(deliveries[0]?.status).toBe('success');
      expect(deliveries[0]?.statusCode).toBe(200);
      expect(deliveries[0]?.registrationId).toBe('webhook-0001');
    });

    it('should record failed deliveries', async () => {
      handler.registerWebhook({
        url: 'https://example.com/hook',
        eventTypes: ['order:created'],
      });

      dispatcher.simulateFailure('Connection refused', 500);
      await eventBus.emit(makeOrderCreatedEvent());

      const deliveries = handler.getDeliveries();
      expect(deliveries).toHaveLength(1);
      expect(deliveries[0]?.status).toBe('failed');
      expect(deliveries[0]?.statusCode).toBe(500);
      expect(deliveries[0]?.error).toBe('Connection refused');
    });

    it('should track deliveries per registration', async () => {
      const reg1 = handler.registerWebhook({
        url: 'https://a.com/hook',
        eventTypes: ['order:created'],
      });
      handler.registerWebhook({
        url: 'https://b.com/hook',
        eventTypes: ['order:created'],
      });

      await eventBus.emit(makeOrderCreatedEvent());

      expect(handler.getDeliveriesForRegistration(reg1.id)).toHaveLength(1);
      expect(handler.getDeliveryCount()).toBe(2);
    });

    it('should record delivery timestamp', async () => {
      handler.registerWebhook({
        url: 'https://example.com/hook',
        eventTypes: ['order:created'],
      });

      const before = new Date();
      await eventBus.emit(makeOrderCreatedEvent());
      const after = new Date();

      const delivery = handler.getDeliveries()[0]!;
      expect(delivery.deliveredAt.getTime()).toBeGreaterThanOrEqual(before.getTime());
      expect(delivery.deliveredAt.getTime()).toBeLessThanOrEqual(after.getTime());
    });

    it('should include the payload in delivery records', async () => {
      handler.registerWebhook({
        url: 'https://example.com/hook',
        eventTypes: ['order:created'],
      });

      await eventBus.emit(makeOrderCreatedEvent());

      const delivery = handler.getDeliveries()[0]!;
      expect(delivery.payload).toMatchObject({
        event: 'order:created',
        orderId: 'order-0001',
      });
      expect(delivery.eventType).toBe('order:created');
    });
  });

  describe('no registrations', () => {
    it('should not dispatch when no webhooks are registered', async () => {
      await eventBus.emit(makeOrderCreatedEvent());

      expect(dispatcher.calls).toHaveLength(0);
      expect(handler.getDeliveryCount()).toBe(0);
    });

    it('should not dispatch after a webhook is unregistered', async () => {
      const reg = handler.registerWebhook({
        url: 'https://example.com/hook',
        eventTypes: ['order:created'],
      });

      handler.unregisterWebhook(reg.id);
      await eventBus.emit(makeOrderCreatedEvent());

      expect(dispatcher.calls).toHaveLength(0);
    });
  });

  describe('clearAll', () => {
    it('should clear registrations and deliveries', async () => {
      handler.registerWebhook({
        url: 'https://example.com/hook',
        eventTypes: ['order:created'],
      });

      await eventBus.emit(makeOrderCreatedEvent());

      handler.clearAll();
      expect(handler.getRegistrations()).toHaveLength(0);
      expect(handler.getDeliveryCount()).toBe(0);
    });
  });

  describe('integration with other handlers', () => {
    it('should work alongside NotificationService on the same EventBus', async () => {
      const { NotificationService } = await import(
        '../../src/services/notification.service.js'
      );
      const notificationService = new NotificationService(eventBus);

      handler.registerWebhook({
        url: 'https://example.com/hook',
        eventTypes: ['order:created'],
      });

      await eventBus.emit(makeOrderCreatedEvent());

      expect(handler.getDeliveryCount()).toBe(1);
      expect(notificationService.getNotificationCount()).toBe(1);
    });

    it('should work alongside EmailNotificationHandler on the same EventBus', async () => {
      const { EmailNotificationHandler } = await import(
        '../../src/notifications/email-handler.js'
      );
      const emailHandler = new EmailNotificationHandler(eventBus);

      handler.registerWebhook({
        url: 'https://example.com/hook',
        eventTypes: ['order:status-changed'],
      });

      await eventBus.emit(makeStatusChangedEvent('pending', 'confirmed'));

      expect(handler.getDeliveryCount()).toBe(1);
      expect(emailHandler.getEmailCount()).toBe(1);
    });
  });
});

